import{_ as o,C as n,o as t,c as i,a2 as a,b as l,w as s,a as d,E as c,a3 as g}from"./chunks/framework.DXCpk3D_.js";const f=JSON.parse('{"title":"What is Open Agent Orchestra?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-oao.md","filePath":"guide/what-is-oao.md"}'),h={name:"guide/what-is-oao.md"};function p(u,e,m,A,b,w){const r=n("Mermaid");return t(),i("div",null,[e[1]||(e[1]=a('<h1 id="what-is-open-agent-orchestra" tabindex="-1">What is Open Agent Orchestra? <a class="header-anchor" href="#what-is-open-agent-orchestra" aria-label="Permalink to &quot;What is Open Agent Orchestra?&quot;">​</a></h1><p><strong>Open Agent Orchestra (OAO)</strong> is an autonomous AI workflow engine powered by the <a href="https://github.com/features/copilot" target="_blank" rel="noreferrer">GitHub Copilot SDK</a>. It lets you build <strong>cost-effective AI teams</strong> — define agents with different skills and cost levels, orchestrate them into multi-step workflows, and run them on schedule, via webhooks, or triggered by system events.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>Many daily tasks can be broken down into multiple smaller tasks that are best solved by <strong>different agents with different roles and skills</strong>:</p><ul><li>A <strong>lower-cost agent</strong> does initial screening, data gathering, and triage</li><li>A <strong>higher-cost agent</strong> with thinking capability and specific domain skills tackles the complex analysis</li><li>A <strong>specialized agent</strong> handles reporting, notifications, or external integrations</li></ul><p>This is exactly how a real team works — people with different capabilities collaborate on problems. We want an <strong>AI team</strong> that is:</p><ul><li><strong>Cost-effective</strong> — Use expensive models only where their reasoning power is needed</li><li><strong>Segregation of duties</strong> — Each agent has a specific role with access only to what it needs</li><li><strong>Secure</strong> — Credentials are accessible in different scopes by tools and never allows agents to access directly</li><li><strong>Auditable</strong> — Full history of what each agent decided and tools were used</li></ul><h3 id="ai-security-challenge" tabindex="-1">AI Security Challenge <a class="header-anchor" href="#ai-security-challenge" aria-label="Permalink to &quot;AI Security Challenge&quot;">​</a></h3><p>When agents interact with external services, they need credentials (API keys, tokens, passwords). Traditional approaches expose credentials as environment variables — with no access control and no way to scope which agent can use what.</p><p><strong>OAO solves this</strong> with a <strong>zero credential exposure</strong> approach:</p><ul><li>Credentials are stored encrypted (AES-256-GCM) and resolved via Jinja2 templates (<span><code>{{ credentials.KEY }}</code></span>)</li><li>Agents never see raw credentials — they are injected into MCP configs and HTTP headers server-side</li><li>Scoped credentials (agent → user → workspace) provide fine-grained access control</li><li>Agents can only access credentials through platform tools — direct access is not permitted</li></ul><h3 id="beyond-just-ai-security" tabindex="-1">Beyond Just AI Security <a class="header-anchor" href="#beyond-just-ai-security" aria-label="Permalink to &quot;Beyond Just AI Security&quot;">​</a></h3><p>Building production AI automation also requires solving infrastructure challenges:</p><ul><li><strong>Scheduling</strong> — Running AI tasks on cron schedules or in response to events</li><li><strong>Orchestration</strong> — Chaining multiple AI steps where each builds on the previous output</li><li><strong>Multi-tenancy</strong> — Isolating agents, workflows, and data across teams</li><li><strong>Error recovery</strong> — Retrying from the failed step, not restarting the entire workflow</li><li><strong>Tool integration</strong> — Giving agents access to APIs, databases, and external services</li></ul><h3 id="enterprise-needs" tabindex="-1">Enterprise Needs <a class="header-anchor" href="#enterprise-needs" aria-label="Permalink to &quot;Enterprise Needs&quot;">​</a></h3><p>Organizations adopting AI automation at scale face additional requirements that OAO addresses:</p><ul><li><p><strong>Workspace isolation</strong> — Each workspace provides a fully isolated boundary for administration, credentials, agents, and workflows. Teams share the same platform without risk of cross-tenant data leakage. Workspace admins manage their own users, rate limits, and secrets independently.</p></li><li><p><strong>Prompt templating with variables</strong> — Workflow steps use Jinja2 templates with user-defined variables (e.g., <span><code>{{ properties.REPORT_DATE }}</code></span>) and webhook payload data (e.g., <span><code>{{ inputs.issue_url }}</code></span>). This eliminates prompt duplication and enables operations teams to configure workflows without modifying agent code.</p></li><li><p><strong>Request usage management</strong> — Workspace defaults and user overrides support daily, weekly, and monthly credit limits. Usage is tracked per user, model, day, and stored credit-cost snapshot so historical totals remain stable even when model records change later.</p></li><li><p><strong>Role-based access control (RBAC)</strong> — Four roles (super_admin, workspace_admin, creator, viewer) control who can create agents, trigger workflows, manage credentials, and access admin functions. Fine-grained scopes on Personal Access Tokens restrict API access for integrations.</p></li><li><p><strong>Agent decision audit trail</strong> — Agents can record structured decisions via the built-in <code>record_decision</code> tool, creating a queryable trail of what was decided, why, and with what confidence. Combined with full step execution logs (including tool calls and reasoning traces), teams can reconstruct any agent&#39;s decision process.</p></li><li><p><strong>Scalable execution architecture</strong> — Each workflow selects a worker runtime: static workers for steady-state queue processing, or ephemeral Kubernetes instances for per-step isolation. This lets teams choose cost versus isolation per workflow.</p></li></ul><h2 id="the-solution" tabindex="-1">The Solution <a class="header-anchor" href="#the-solution" aria-label="Permalink to &quot;The Solution&quot;">​</a></h2><p>OAO provides all of this as a single, self-hosted platform:</p>',19)),(t(),l(g,null,{default:s(()=>[c(r,{id:"mermaid-162",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20subgraph%20%22Agent%20Definition%22%0A%20%20%20%20%20%20%20%20MD%5BAgent%20Markdown%3Cbr%2F%3Epersonality%20%2B%20instructions%5D%0A%20%20%20%20%20%20%20%20SK%5BSkills%3Cbr%2F%3Edomain%20knowledge%20.md%20files%5D%0A%20%20%20%20%20%20%20%20MCP%5BMCP%20Servers%3Cbr%2F%3Ecustom%20tool%20endpoints%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22Workflow%20Engine%22%0A%20%20%20%20%20%20%20%20WF%5BWorkflow%3Cbr%2F%3Eordered%20steps%20%2B%20per-step%20model%5D%0A%20%20%20%20%20%20%20%20TR%5BTriggers%3Cbr%2F%3Ecron%20%2F%20event%20%2F%20webhook%20%2F%20manual%5D%0A%20%20%20%20%20%20%20%20EX%5BExecution%20Engine%3Cbr%2F%3Estep-by-step%20with%20retry%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22Runtime%22%0A%20%20%20%20%20%20%20%20CS%5BCopilot%20Session%3Cbr%2F%3EGitHub%20Copilot%20SDK%5D%0A%20%20%20%20%20%20%20%20BT%5BBuilt-in%20Tools%3Cbr%2F%3E9%20platform%20tools%5D%0A%20%20%20%20%20%20%20%20SEC%5BSecurity%20Audit%3Cbr%2F%3Ecredential%20approval%20agent%5D%0A%20%20%20%20end%0A%0A%20%20%20%20MD%20--%3E%20CS%0A%20%20%20%20SK%20--%3E%20CS%0A%20%20%20%20MCP%20--%3E%20CS%0A%20%20%20%20TR%20--%3E%20WF%0A%20%20%20%20WF%20--%3E%20EX%0A%20%20%20%20EX%20--%3E%20CS%0A%20%20%20%20BT%20--%3E%20CS%0A%20%20%20%20SEC%20--%3E%7Capprove%2Fdeny%7C%20BT%0A"})]),fallback:s(()=>[...e[0]||(e[0]=[d(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<div class="mermaid-source" data-mermaid-source=""></div><h2 id="architecture-at-a-glance" tabindex="-1">Architecture at a Glance <a class="header-anchor" href="#architecture-at-a-glance" aria-label="Permalink to &quot;Architecture at a Glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>OAO-API</strong></td><td>REST API for agents, workflows, triggers, executions</td></tr><tr><td><strong>OAO-UI</strong></td><td>Dashboard for managing everything</td></tr><tr><td><strong>OAO-Controller</strong></td><td>Polls triggers, dispatches workflows, provisions agent instances</td></tr><tr><td><strong>Agent Workers</strong></td><td>Execute workflow steps via Copilot sessions</td></tr><tr><td><strong>PostgreSQL</strong></td><td>Persistent storage with pgvector embeddings</td></tr><tr><td><strong>Redis + BullMQ</strong></td><td>Job queues for workflow and step execution</td></tr><tr><td><strong>GitHub Copilot SDK</strong></td><td>Creates and manages AI sessions</td></tr></tbody></table><p>All backend roles (API, Controller, Agent Worker) run from a single <code>oao-core</code> Docker image — the role is selected by the container command at runtime.</p><h2 id="who-is-this-for" tabindex="-1">Who Is This For? <a class="header-anchor" href="#who-is-this-for" aria-label="Permalink to &quot;Who Is This For?&quot;">​</a></h2><ul><li><strong>DevOps teams</strong> automating recurring analysis and reporting with cost control</li><li><strong>AI engineers</strong> building multi-agent pipelines with different model tiers</li><li><strong>Platform teams</strong> providing AI automation as a shared service with proper security</li><li><strong>Developers</strong> who want agent orchestration without building infrastructure</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/open-agent-orchestra/1.30.11/guide/docker.html">Host on Docker</a> — Run OAO with Docker (no build required)</li><li><a href="/open-agent-orchestra/1.30.11/guide/kubernetes.html">Host on Kubernetes</a> — Run OAO on Kubernetes with Helm</li><li><a href="/open-agent-orchestra/1.30.11/guide/build-and-deploy.html">Build &amp; Deploy</a> — Checkout source code and build from scratch</li><li><a href="/open-agent-orchestra/1.30.11/concepts/agents.html">Agents &amp; Tools</a> — Understand agents and the tool system</li><li><a href="/open-agent-orchestra/1.30.11/concepts/security.html">AI Security</a> — Zero credential exposure with Jinja2 templates</li><li><a href="/open-agent-orchestra/1.30.11/concepts/auth-providers.html">Auth Providers</a> — Database + LDAP/Active Directory authentication</li></ul>',8))])}const I=o(h,[["render",p]]);export{f as __pageData,I as default};
